import os
from flask import Flask, jsonify, send_file, request

app = Flask(__name__)
ROOT_DIR = '/path/to/your/root'  # Replace this with your root path

@app.route('/list', methods=['GET'])
def list_dir():
    dir_path = request.args.get('dir')
    if not dir_path:
        return jsonify({"error": "No directory specified"}), 400
    
    full_path = os.path.normpath(os.path.join(ROOT_DIR, dir_path))
    # Ensure path is within root directory to prevent directory traversal
    if not full_path.startswith(ROOT_DIR):
        return jsonify({"error": "Invalid path"}), 403
    
    try:
        files = os.listdir(full_path)
        return jsonify(files), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

